// Parse CSV and compute sales metrics
const rows = $input.first().binary.data.toString('utf8')
  .trim().split('\n').slice(1)
  .map(r => r.split(','));

let totalRevenue = 0, totalUnits = 0, catRevenue = {};
for (const [date, product, category, price, discount, units, revenue] of rows) {
  totalRevenue += parseFloat(revenue) || 0;
  totalUnits   += parseInt(units) || 0;
  catRevenue[category] = (catRevenue[category] || 0) + (parseFloat(revenue) || 0);
}

const topCategory = Object.entries(catRevenue).sort((a,b)=>b[1]-a[1])[0];

return [{
  json: {
    total_revenue: totalRevenue.toFixed(2),
    total_units:   totalUnits,
    top_category:  topCategory[0],
    top_cat_revenue: topCategory[1].toFixed(2),
    category_breakdown: catRevenue,
    metrics_text: `Total Revenue: INR ${totalRevenue.toFixed(0)}\nUnits Sold: ${totalUnits}\nTop Category: ${topCategory[0]} (INR ${topCategory[1].toFixed(0)})`
  }
}];

// Parse reviews CSV and build batch sentiment input
const rows = $input.first().binary.data.toString('utf8')
  .trim().split('\n').slice(1)
  .map(r => {
    const parts = r.split(',');
    return { id: parts[0], product: parts[1], text: parts.slice(3).join(',') };
  });

const reviewsForPrompt = rows
  .map(r => `${r.id}. [${r.product}] ${r.text}`).join('\n');

return [{ json: { reviews: rows, prompt_input: reviewsForPrompt } }];

