const reportContent = $input.first().json.choices[0].message.content;
const metricsNode = $('Compute Sales Metrics').first().json;

const fullReport = `# AI Business Report
**Generated:** ${new Date().toISOString().split('T')[0]}

## Key Metrics
- Total Revenue: INR ${metricsNode.total_revenue}
- Units Sold: ${metricsNode.total_units}
- Top Category: ${metricsNode.top_category}

---

${reportContent}
`;

return [{ json: { report: fullReport, filename: 'business_report.md' } }];

const raw = $input.first().json.choices[0].message.content;
const lines = raw.trim().split('\n').filter(l => l.includes('|'));

let pos=0, neg=0, neu=0;
for (const line of lines) {
  const parts = line.split('|');
  if (parts[1]) {
    const s = parts[1].trim().toLowerCase();
    if (s === 'positive') pos++;
    else if (s === 'negative') neg++;
    else neu++;
  }
}
const total = pos+neg+neu;

const summary = `# Sentiment Report\n**Generated:** ${new Date().toISOString().split('T')[0]}\n\n## Breakdown\n- Positive: ${pos} (${(pos/total*100).toFixed(1)}%)\n- Negative: ${neg} (${(neg/total*100).toFixed(1)}%)\n- Neutral: ${neu} (${(neu/total*100).toFixed(1)}%)\n`;

return [{ json: { report: summary, filename: 'sentiment_report.md', pos, neg, neu } }];
